import { cn } from "@/lib/utils";

const sizeMap = {
  default: { jukubox: "text-xl", dotAi: "text-sm" },
  lg: { jukubox: "text-3xl", dotAi: "text-lg" },
  exlg: { jukubox: "text-7xl lg:text-8xl", dotAi: "text-4xl lg:text-5xl" },
} as const;

type Size = keyof typeof sizeMap;

export function JukuBoxLogo({ size = "default" }: { size?: Size }) {
  const { jukubox, dotAi } = sizeMap[size];

  return (
    <span className="flex items-baseline gap-0.5 font-orbitron">
      <span
        className={cn(
          "font-black [text-shadow:0_0_18px_oklch(0.75_0.12_77/0.45)] text-primary",
          jukubox,
        )}
      >
        JukuBox
      </span>
      <span className={cn("font-bold text-secondary", dotAi)}>.ai</span>
    </span>
  );
}

"use client";

import { createClient } from "@/lib/supabase/client";

export function OAuthLoginButton() {
  const handleGoogleLogin = async () => {
    const supabase = createClient();
    await supabase.auth.signInWithOAuth({
      provider: "google",
      options: {
        redirectTo: `${location.origin}/auth/callback`,
      },
    });
  };

  return (
    <button
      type="button"
      onClick={handleGoogleLogin}
      className="flex items-center gap-3 rounded border border-gray-300 bg-white px-6 py-3 text-sm font-medium text-gray-700 shadow-sm hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2"
    >
      <GoogleLogo />
      Sign in with Google
    </button>
  );
}

function GoogleLogo() {
  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      viewBox="0 0 48 48"
      width="18"
      height="18"
    >
      <path
        fill="#4285F4"
        d="M45.12 24.5c0-1.56-.14-3.06-.4-4.5H24v8.51h11.84c-.51 2.75-2.06 5.08-4.39 6.64v5.52h7.11c4.16-3.83 6.56-9.47 6.56-16.17z"
      />
      <path
        fill="#34A853"
        d="M24 46c5.94 0 10.92-1.97 14.56-5.33l-7.11-5.52c-1.97 1.32-4.49 2.1-7.45 2.1-5.73 0-10.58-3.87-12.31-9.07H4.34v5.7C7.96 41.07 15.4 46 24 46z"
      />
      <path
        fill="#FBBC05"
        d="M11.69 28.18C11.25 26.86 11 25.45 11 24s.25-2.86.69-4.18v-5.7H4.34C2.85 17.09 2 20.45 2 24c0 3.55.85 6.91 2.34 9.88l7.35-5.7z"
      />
      <path
        fill="#EA4335"
        d="M24 10.75c3.23 0 6.13 1.11 8.41 3.29l6.31-6.31C34.91 4.18 29.93 2 24 2 15.4 2 7.96 6.93 4.34 14.12l7.35 5.7c1.73-5.2 6.58-9.07 12.31-9.07z"
      />
    </svg>
  );
}

